const workflow = $json.body;
const errors = [];
const warnings = [];

if (!workflow.name) errors.push('Missing workflow name');
if (!workflow.nodes || !Array.isArray(workflow.nodes)) {
  errors.push('Missing or invalid nodes array');
  return [{ json: { workflow, errors, warnings, structureValid: false } }];
}
if (!workflow.connections || typeof workflow.connections !== 'object') {
  errors.push('Missing or invalid connections object');
}

const nodeNames = new Set();
const nodeIds = new Set();
let triggerCount = 0;

for (const node of workflow.nodes) {
  if (!node.name) errors.push(`Node missing name (id: ${node.id})`);
  if (!node.type) errors.push(`Node '${node.name}' missing type`);
  if (!node.typeVersion) warnings.push(`Node '${node.name}' missing typeVersion`);
  if (!node.position) warnings.push(`Node '${node.name}' missing position`);

  if (nodeNames.has(node.name)) errors.push(`Duplicate node name: '${node.name}'`);
  nodeNames.add(node.name);

  if (node.id) {
    if (nodeIds.has(node.id)) errors.push(`Duplicate node ID: '${node.id}'`);
    nodeIds.add(node.id);
  }

  if (node.type && (node.type.includes('Trigger') || node.type.includes('webhook'))) {
    triggerCount++;
  }
}

if (triggerCount === 0) warnings.push('No trigger node found');
if (triggerCount > 1) warnings.push(`Multiple triggers found (${triggerCount})`);

const connectedNodes = new Set();
for (const [sourceName, outputs] of Object.entries(workflow.connections || {})) {
  connectedNodes.add(sourceName);
  if (outputs.main) {
    for (const branch of outputs.main) {
      if (Array.isArray(branch)) {
        for (const conn of branch) {
          connectedNodes.add(conn.node);
        }
      }
    }
  }
}

for (const node of workflow.nodes) {
  if (!connectedNodes.has(node.name) && !node.type.includes('Trigger') && !node.type.includes('webhook')) {
    warnings.push(`Orphan node: '${node.name}' has no connections`);
  }
}

for (const [sourceName, outputs] of Object.entries(workflow.connections || {})) {
  if (!nodeNames.has(sourceName)) {
    errors.push(`Connection references non-existent source: '${sourceName}'`);
  }
  if (outputs.main) {
    for (const branch of outputs.main) {
      if (Array.isArray(branch)) {
        for (const conn of branch) {
          if (!nodeNames.has(conn.node)) {
            errors.push(`Connection from '${sourceName}' targets non-existent node: '${conn.node}'`);
          }
        }
      }
    }
  }
}

return [{ json: { workflow, errors, warnings, structureValid: errors.length === 0, nodeCount: workflow.nodes.length, triggerCount } }];

const input = $input.first().json;
const workflow = input.workflow;
const errors = [...input.errors];
const warnings = [...input.warnings];
const findings = [];

if (!workflow.nodes) {
  return [{ json: { ...input, securityFindings: findings, securityPass: true } }];
}

const secretPatterns = [
  { regex: /sk-[a-zA-Z0-9]{20,}/, label: 'OpenAI API key' },
  { regex: /xoxb-[a-zA-Z0-9-]+/, label: 'Slack bot token' },
  { regex: /ghp_[a-zA-Z0-9]{36}/, label: 'GitHub PAT' },
  { regex: /password\s*[:=]\s*['"][^'"]{8,}['"]/, label: 'Hardcoded password' }
];

for (const node of workflow.nodes) {
  const nodeStr = JSON.stringify(node.parameters || {});

  for (const pattern of secretPatterns) {
    if (pattern.regex.test(nodeStr)) {
      errors.push(`SECURITY: '${node.name}' may contain ${pattern.label}`);
      findings.push({ node: node.name, type: 'hardcoded_secret', detail: pattern.label });
    }
  }

  if (node.type === 'n8n-nodes-base.executeCommand') {
    warnings.push(`SECURITY: '${node.name}' uses Execute Command`);
    findings.push({ node: node.name, type: 'dangerous_node', detail: 'executeCommand' });
  }

  if (node.type === 'n8n-nodes-base.code') {
    const code = node.parameters?.jsCode || node.parameters?.pythonCode || '';
    const hasEval = code.indexOf('eval(') !== -1;
    const hasNewFunc = code.indexOf('new Function(') !== -1;
    if (hasEval) {
      errors.push(`SECURITY: '${node.name}' uses eval()`);
      findings.push({ node: node.name, type: 'code_injection', detail: 'eval()' });
    }
    if (hasNewFunc) {
      errors.push(`SECURITY: '${node.name}' uses new Function()`);
      findings.push({ node: node.name, type: 'code_injection', detail: 'new Function()' });
    }
  }

  if (node.type === 'n8n-nodes-base.webhook') {
    const hasAuth = node.parameters?.authentication && node.parameters.authentication !== 'none';
    if (!hasAuth) {
      warnings.push(`SECURITY: Webhook '${node.name}' has no authentication`);
      findings.push({ node: node.name, type: 'open_webhook', detail: 'no auth' });
    }
  }
}

const securityPass = !findings.some(f => f.type === 'hardcoded_secret' || f.type === 'code_injection');
return [{ json: { ...input, errors, warnings, securityFindings: findings, securityPass } }];

const input = $input.first().json;
const workflow = input.workflow;

const nodeCount = input.nodeCount || 0;
const connectionCount = Object.keys(workflow.connections || {}).length;
let branchCount = 0;
for (const outputs of Object.values(workflow.connections || {})) {
  if (outputs.main && outputs.main.length > 1) {
    branchCount += outputs.main.length - 1;
  }
}

let complexityScore = 'simple';
if (nodeCount > 15 || branchCount > 3) complexityScore = 'complex';
else if (nodeCount > 7 || branchCount > 1) complexityScore = 'medium';

const errorCount = input.errors.length;
const warningCount = input.warnings.length;
let verdict = 'PASS';
if (errorCount > 0) verdict = 'FAIL';
else if (warningCount > 3) verdict = 'REVIEW';

return [{ json: {
  verdict,
  workflowName: workflow.name || 'Unnamed',
  timestamp: DateTime.now().toISO(),
  structure: { valid: input.structureValid, nodeCount, connectionCount, triggerCount: input.triggerCount, branchCount },
  security: { pass: input.securityPass, findings: input.securityFindings || [] },
  complexity: { score: complexityScore, recommendation: complexityScore === 'complex' ? 'Consider splitting into sub-workflows' : null },
  errors: input.errors,
  warnings: input.warnings,
  errorCount,
  warningCount,
  summary: `${verdict}: ${errorCount} errors, ${warningCount} warnings | ${complexityScore} (${nodeCount} nodes, ${branchCount} branches)`
} }];

const input = $input.first().json;

const message = input.message || 'No message provided';
const severity = (input.severity || 'low').toLowerCase();
const channel = input.channel || 'default';
const metadata = input.metadata || {};
const timestamp = DateTime.now().toISO();

const severityConfig = {
  critical: { emoji: '\ud83d\udea8', prefix: 'CRITICAL', channels: ['slack', 'email', 'discord'] },
  high:     { emoji: '\u26a0\ufe0f', prefix: 'HIGH', channels: ['slack', 'email'] },
  medium:   { emoji: '\ud83d\udfe1', prefix: 'MEDIUM', channels: ['slack'] },
  low:      { emoji: '\u2139\ufe0f', prefix: 'LOW', channels: ['log'] }
};

const config = severityConfig[severity] || severityConfig.low;
const targetChannels = channel === 'default' ? config.channels : [channel];

const formatted = {
  timestamp,
  severity,
  originalMessage: message,
  metadata,
  channels: targetChannels,
  formatted: {
    slack: `${config.emoji} *[${config.prefix}]* ${message}`,
    email: {
      subject: `[${config.prefix}] n8n Alert: ${message.substring(0, 80)}`,
      body: `Severity: ${config.prefix}\nTime: ${timestamp}\n\n${message}\n\nMetadata: ${JSON.stringify(metadata, null, 2)}`
