const headers = input.headers || {};
const body = input.body || null;
const maxRetries = input.maxRetries || 3;
const baseDelayMs = input.baseDelayMs || 1000;
const timeoutMs = input.timeoutMs || 30000;

if (!url) {
  return [{ json: { success: false, error: 'No URL provided', attempts: 0 } }];
}

let lastError = null;
let attempts = 0;

for (let i = 0; i <= maxRetries; i++) {
  attempts = i + 1;

  if (i > 0) {
    const delay = baseDelayMs * Math.pow(2, i - 1);
    const jitter = Math.random() * delay * 0.1;
    await new Promise(resolve => setTimeout(resolve, delay + jitter));
  }

  try {
    const requestConfig = {
      method,
      url,
      headers,
      timeout: timeoutMs,
      returnFullResponse: true
    };

    if (body && ['POST', 'PUT', 'PATCH'].includes(method)) {
      requestConfig.body = typeof body === 'string' ? body : JSON.stringify(body);
      if (!headers['Content-Type']) {
        requestConfig.headers['Content-Type'] = 'application/json';
      }
    }

    const response = await $helpers.httpRequest(requestConfig);

    return [{ json: { success: true, data: response, attempts, url, method } }];
  } catch (error) {
    lastError = error;

    if (error.statusCode && error.statusCode >= 400 && error.statusCode < 500 && error.statusCode !== 429) {
      return [{ json: { success: false, error: error.message, statusCode: error.statusCode, attempts, retriable: false, url, method } }];
    }
  }
}

return [{ json: { success: false, error: lastError ? lastError.message : 'Max retries exceeded', statusCode: lastError ? lastError.statusCode : null, attempts, retriable: true, url, method } }];

