  if (labelsStr.includes('URGENT')) {
    route = 'urgent';
  } else if (labelsStr.includes('Birthday') || labelsStr.includes('Anniversary')) {
    route = 'birthday';
  } else if (labelsStr.includes('Financial')) {
    route = 'financial';
  }

  results.push({
    json: {
      route,
      content,
      labels: labelsStr,
      taskId,
      projectId
    }
  });
}

return results;
